+func TestAsInt64(t *testing.T) {
+	tests := []struct {
+		name     string
+		input    any
+		wantVal  int64
+		wantOK   bool
+	}{
+		{
+			name:    "float64 positive",
+			input:   float64(123.0),
+			wantVal: 123,
+			wantOK:  true,
+		},
+		{
+			name:    "float64 with decimals",
+			input:   float64(456.789),
+			wantVal: 456, // truncated
+			wantOK:  true,
+		},
+		{
+			name:    "int64 positive",
+			input:   int64(999),
+			wantVal: 999,
+			wantOK:  true,
+		},
+		{
+			name:    "int positive",
+			input:   int(12345),
+			wantVal: 12345,
+			wantOK:  true,
+		},
+		{
+			name:    "json.Number integer",
+			input:   json.Number("67890"),
+			wantVal: 67890,
+			wantOK:  true,
+		},
+		{
+			name:    "json.Number float",
+			input:   json.Number("123.456"),
+			wantVal: 123,
+			wantOK:  true,
+		},
+		{
+			name:    "string numeric",
+			input:   "54321",
+			wantVal: 54321,
+			wantOK:  true,
+		},
+		{
+			name:    "string non-numeric",
+			input:   "hello",
+			wantVal: 0,
+			wantOK:  false,
+		},
+		{
+			name:    "nil",
+			input:   nil,
+			wantVal: 0,
+			wantOK:  false,
+		},
+		{
+			name:    "bool",
+			input:   true,
+			wantVal: 0,
+			wantOK:  false,
+		},
+		{
+			name:    "slice",
+			input:   []int{1, 2, 3},
+			wantVal: 0,
+			wantOK:  false,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			t.Logf("[TEST] Input: %v (%T)", tt.input, tt.input)
+			val, ok := asInt64(tt.input)
+			t.Logf("[TEST] Result: val=%d, ok=%v", val, ok)
+
+			if val != tt.wantVal {
+				t.Errorf("asInt64() value = %d, want %d", val, tt.wantVal)
+			}
+			if ok != tt.wantOK {
+				t.Errorf("asInt64() ok = %v, want %v", ok, tt.wantOK)
+			}
+		})
+	}
+}
+
+func TestAsMap(t *testing.T) {
+	t.Run("valid map", func(t *testing.T) {
+		input := map[string]any{"key": "value"}
+		m, ok := asMap(input)
+		if !ok {
+			t.Error("asMap() returned false for valid map")
+		}
+		if m["key"] != "value" {
+			t.Errorf("asMap() map[key] = %v, want value", m["key"])
+		}
+	})
+
+	t.Run("invalid type", func(t *testing.T) {
+		input := "not a map"
+		_, ok := asMap(input)
+		if ok {
+			t.Error("asMap() returned true for non-map")
+		}
+	})
+}
