+			wantOutput: 50,
+			wantTotal:  150, // input+output (cache tracked separately)
+		},
+		{
+			name:       "empty usage",
+			input:      `{}`,
+			wantInput:  0,
+			wantOutput: 0,
+			wantTotal:  0,
+		},
